536													condensed_features: { query: normalizedQuery, boost: 0.3 },
537												},
538											},
539											...priceBoosts,
540											...brandBoosts,
541											...genderBoosts,
542											...colorBoosts,
543											...sizeBoosts,
544											...unitPriceBoosts,
545										],
