592			responseFormatter: (response: IOpensearchProduct[]) => ({
593				total: response.length,
594			}),
595		})
596		async searchProductsByCategories({
597			categories,
598			size,
599		}: {
600			categories: Record<string, string>[];
601			size?: number;
602		}): Promise<IOpensearchProduct[]> {
603			const effectiveSize = size ?? NEURAL_SEARCH_LIMIT;
604			const perCategory = Math.ceil(effectiveSize / categories.length);
605	
606			const categoryResults = await Promise.all(
607				categories.map((categoryEntry) => {
608					const categoryName = Object.keys(categoryEntry)[0] ?? '';
609					const categoryQueryText = Object.values(categoryEntry)[0] ?? '';
610	
611					return this.searchProducts({
612						queryText: categoryQueryText || categoryName,
613						size: perCategory,
614						categoryFilter: categoryName,
615					});
616				}),
617			);
618	
619			const interleaved: IOpensearchProduct[] = [];
620			const maxLen = Math.max(...categoryResults.map((r) => r.length));
621			for (let i = 0; i < maxLen; i++) {
622				for (const results of categoryResults) {
623					const item = results[i];
624					if (item !== undefined) {
625						interleaved.push(item);
626					}
627				}
628			}
629	
630			return interleaved.slice(0, effectiveSize);
631		}
632	
633		private resolveColorImageUrl({
634			product,
635			colorName,
636		}: {
637			product: IOpensearchProduct;
638			colorName: string;
639		}): string | null {
640			if (!product.colors?.length) return null;
641	
642			const lowerColor = colorName.toLowerCase();
643			const match = product.colors.find((c) => c.name.toLowerCase() === lowerColor);
644	
645			if (match?.image_url) return match.image_url;
646	
647			const partialMatch = product.colors.find((c) =>
648				c.name.toLowerCase().includes(lowerColor),
649			);
650	
651			return partialMatch?.image_url ?? null;
652		}
653	
654		private normalizeCondensedFeatures({
655			condensedFeatures,
656		}: {
657			condensedFeatures: unknown;
658		}): string[] | null {
659			if (condensedFeatures === null || condensedFeatures === undefined) {
660				return null;
661			}
662	
663			if (typeof condensedFeatures === 'string') {
664				return [condensedFeatures];
665			}
666	
667			if (Array.isArray(condensedFeatures)) {
668				return condensedFeatures.map(String);
669			}
670	
671			if (typeof condensedFeatures === 'object') {
672				return Object.values(condensedFeatures).flatMap((value: unknown) =>
673					Array.isArray(value) ? value.map(String) : [String(value)],
674				);
675			}
676	
677			return [JSON.stringify(condensedFeatures)];
678		}
679	
680		private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
681			const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
682				condensedFeatures: style.condensed_features,
683			});
684			const priceLvlMap: Record<string, string> = {
685				1: 'Budget',
686				2: 'Mid-range',
687				3: 'Premium',
688			};
689			const mappedPriceLevel: string | null =
690				style.price_level && priceLvlMap[String(style.price_level)]
691					? (priceLvlMap[String(style.price_level)] ?? null)
692					: (priceLvlMap['2'] ?? null);
693	
694			const parts: string[] = [
695				...(style.name ? [this.cleanText({ text: style.name })] : []),
696				...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
697				...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
698				...(style.brand?.length
699					? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
700					: []),
701				...(normalizedCondensedFeatures?.length
702					? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
703					: []),
704				...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
705				...(style.primary_category_name
706					? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
707					: []),
708				...(style.manufacturer
709					? [`From: ${this.cleanText({ text: style.manufacturer })}`]
710					: []),
711				...(style.sub_category_names?.length
712					? [
713							`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
714						]
715					: []),
716				...(style.decoration_method
717					? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
718					: []),
719				...(style.features
720					? [`Features: ${this.cleanText({ text: style.features })}`]
721					: []),
722			];
723	
724			const combinedText = parts.filter(Boolean).join('. ');
725	
726			this.logger.debug(
727				`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
728			);
729	
730			return combinedText;
731		}
732	
733		private extractPrice({
734			prices,
735		}: {
736			prices: IOpensearchProduct['default_unit_prices'];
737		}): number | null {
738			if (!prices?.length) return null;
739			const first = prices[0];
740			if (!first) return null;
741			const parsed = parseFloat(first.price);
742			return isNaN(parsed) ? null : parsed;
743		}
744	
745		private cleanText({ text }: { text: string | null | undefined }): string {
746			if (!text) return '';
747			return text
748				.replace(/\r\n|\r|\n/g, ' ')
749				.replace(/[*#]+\s?/g, '')
750				.replace(/<[^>]*>/g, '')
751				.replace(/\s{2,}/g, ' ')
752				.trim();
753		}
754	
755		private transformStyleToOpensearchProduct({
756			style,
757		}: {
758			style: IStylesMvBase;
759		}): IOpensearchProduct {
760			return {
761				_id: style._id,
762				style_id: style.style_id,
763				product_id: style.product_id,
764				name: style.name ?? '',
765				features: style.features,
766				general_comments: style.general_comments,
767				decoration_method: style.decoration_method,
768				manufacturer: style.manufacturer,
769				primary_category_id: style.primary_category_id,
770				primary_category_name: style.primary_category_name,
771				product_type: style.product_type,
772				style_type: style.style_type,
773				broad_category_names: style.broad_category_names,
774				sub_category_names: style.sub_category_names,
775				minimum_quantity: style.minimum_quantity,
776				min_qty: style.min_qty,
777				default_quote_qty: style.default_quote_qty,
778				sizes: style.sizes,
779				turn_time: style.turn_time,
780				rush_turn_time: style.rush_turn_time,
781				no_minimum: style.no_minimum ? 1 : 0,
782				price_level: style.price_level,
783				rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
784				rating_count: style.rating_count,
785				default_unit_prices: style.default_unit_prices,
786				price: this.extractPrice({ prices: style.default_unit_prices }),
787				colors: style.colors,
788				style_card_image_url: style.style_card_image_url,
789				link: style.link,
790				brand: style.brand,
791				condensed_features: this.normalizeCondensedFeatures({
792					condensedFeatures: style.condensed_features,
793				}),
794				material: style.material,
795				status: style.status,
796				created_at:
797					style.created_at instanceof Date
798						? style.created_at.toISOString()
799						: String(style.created_at),
800				updated_at:
801					style.updated_at instanceof Date
802						? style.updated_at.toISOString()
803						: String(style.updated_at),
804				deleted_at: style.deleted_at
805					? style.deleted_at instanceof Date
806						? style.deleted_at.toISOString()
807						: String(style.deleted_at)
808					: null,
809				combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
810			};
811		}
812	}
