import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { Interval } from '@nestjs/schedule';

import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { OpensearchService } from '@modules/opensearch/opensearch.service';

import {
	NEURAL_SEARCH_LIMIT,
	NEURAL_SEARCH_MAX_QUERY_LENGTH,
} from '@constants/common.constant';
import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
import {
	NEURAL_SEARCH_CONTRACTIONS,
	NEURAL_SEARCH_KNOWN_BRANDS,
	NEURAL_SEARCH_KNOWN_COLORS,
	NEURAL_SEARCH_KNOWN_SIZES,
} from '@constants/neural-search.constant';

import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';

import { LogExecution } from '@decorators/log-execution.decorator';

const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;

const MODEL_GROUP_NAME = 'neural-search-model-group';

@Injectable()
export class OpensearchNeuralService implements OnModuleInit {
	private readonly logger = new Logger(OpensearchNeuralService.name);
	private indexName: string;
	private modelId: string | null = null;

	constructor(
		private readonly opensearchService: OpensearchService,
		private readonly configService: EnvConfigService,
	) {}

	async onModuleInit(): Promise<void> {
		this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
		await this.resolveModelId();
	}

	@Interval(MODEL_REFRESH_INTERVAL_MS)
	async refreshModelId(): Promise<void> {
		await this.resolveModelId();
	}

	private async resolveModelId(): Promise<void> {
		try {
			const modelId = await this.opensearchService.findDeployedModelId({
				modelGroupName: MODEL_GROUP_NAME,
			});

			if (modelId && modelId !== this.modelId) {
				const previousModelId = this.modelId;
				this.modelId = modelId;
				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
			} else if (!modelId) {
				this.logger.warn(
					'No deployed model found. Neural search will not work until bootstrap is run.',
				);
			}
		} catch {
			this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
		}
	}

	private getModelId(): string {
		if (!this.modelId) {
			throw new Error(
				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
			);
		}
		return this.modelId;
	}

	private detectBrand({ text }: { text: string }): string | null {
		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
		for (const brand of sorted) {
			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
				return brand;
			}
		}
		return null;
	}

	private detectColor({ text }: { text: string }): string | null {
		const sorted = [...NEURAL_SEARCH_KNOWN_COLORS].sort((a, b) => b.length - a.length);
		for (const color of sorted) {
			const escaped = color.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
				return color;
			}
		}
		return null;
	}

	private readonly MEASUREMENT_UNITS_PATTERN =
		/\b\d+\s*(?:oz|ounce|ml|liter|litre|gal|gallon|inch|in|cm|mm|ft|foot|feet)\b/i;

	private readonly PRICE_RANGE_PATTERNS: {
		pattern: RegExp;
		extract: ({
			match,
		}: {
			match: RegExpExecArray;
		}) => { min: number | null; max: number | null } | null;
	}[] = [
		{
			pattern: /\b(?:under|below|less\s+than|up\s+to)\s+\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const max = parseFloat(match[1] ?? '');
				return isNaN(max) ? null : { min: null, max };
			},
		},
		{
			pattern: /\bfrom\s+\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const min = parseFloat(match[1] ?? '');
				const max = parseFloat(match[2] ?? '');
				return isNaN(min) || isNaN(max) ? null : { min, max };
			},
		},
		{
			pattern: /\$(\d+(?:\.\d{1,2})?)\s*[-–]\s*\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const min = parseFloat(match[1] ?? '');
				const max = parseFloat(match[2] ?? '');
				return isNaN(min) || isNaN(max) ? null : { min, max };
			},
		},
		{
			pattern: /\$(\d+(?:\.\d{1,2})?)\s+to\s+\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const min = parseFloat(match[1] ?? '');
				const max = parseFloat(match[2] ?? '');
				return isNaN(min) || isNaN(max) ? null : { min, max };
			},
		},
		{
			pattern: /\bto\s+\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const max = parseFloat(match[1] ?? '');
				return isNaN(max) ? null : { min: null, max };
			},
		},
		{
			pattern: /\b(?:over|above|more\s+than|from)\s+\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const min = parseFloat(match[1] ?? '');
				return isNaN(min) ? null : { min, max: null };
			},
		},
		{
			pattern: /\b(?:around|about|~)\s*\$(\d+(?:\.\d{1,2})?)/i,
			extract: ({ match }) => {
				const price = parseFloat(match[1] ?? '');
				return isNaN(price)
					? null
					: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
			},
		},
		{
			pattern: /\$(\d+(?:\.\d{1,2})?)/,
			extract: ({ match }) => {
				const price = parseFloat(match[1] ?? '');
				return isNaN(price)
					? null
					: { min: Math.round(price * 0.8), max: Math.round(price * 1.2) };
			},
		},
	];

	private detectPriceRange({
		text,
	}: {
		text: string;
	}): { min: number | null; max: number | null } | null {
		for (const { pattern, extract } of this.PRICE_RANGE_PATTERNS) {
			const match = pattern.exec(text);
			if (match) {
				return extract({ match });
			}
		}
		return null;
	}

	private stripContractions({ text }: { text: string }): string {
		let result = text;
		for (const contraction of NEURAL_SEARCH_CONTRACTIONS) {
			result = result.replace(new RegExp(`\\b${contraction}\\b`, 'gi'), '');
		}
		return result;
	}

	private readonly PRICE_STRIP_PATTERN =
		/\b(?:under|below|less\s+than|up\s+to|over|above|more\s+than|from|around|about|~)?\s*\$\d+(?:\.\d{1,2})?\s*(?:[-–]\s*\$\d+(?:\.\d{1,2})?)?\b/gi;

	private detectSize({ text }: { text: string }): string | null {
		const cleanedText = this.stripContractions({
			text: text
				.replace(this.MEASUREMENT_UNITS_PATTERN, '')
				.replace(this.PRICE_STRIP_PATTERN, ''),
		});
		const sorted = [...NEURAL_SEARCH_KNOWN_SIZES].sort((a, b) => b.length - a.length);
		for (const size of sorted) {
			const escaped = size.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
			if (new RegExp(`\\b${escaped}\\b`, 'i').test(cleanedText)) {
				return size;
			}
		}
		return null;
	}

	private readonly GENDER_PRODUCT_TYPE_MAP: {
		pattern: RegExp;
		productTypes: string[];
	}[] = [
		{
			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
			productTypes: ["Women's"],
		},
		{
			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
			productTypes: ['Unisex'],
		},
		{
			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
			productTypes: ['Youth'],
		},
	];

	private detectGenderProductTypes({ text }: { text: string }): string[] | null {
		const productTypes: string[] = [];

		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
			if (pattern.test(text)) {
				productTypes.push(...types);
			}
		}

		return productTypes.length > 0 ? productTypes : null;
	}

	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
		{
			pattern:
				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
			levels: [1],
		},
		{
			pattern:
				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
			levels: [2],
		},
		{
			pattern:
				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest|high[\s-]quality)\b/i,
			levels: [3],
		},
	];

	private detectPriceLevels({ text }: { text: string }): number[] | null {
		const levels: number[] = [];

		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
			if (pattern.test(text)) {
				levels.push(...priceLevels);
			}
		}

		return levels.length > 0 ? levels : null;
	}

	private sanitizeQuery({ text }: { text: string }): string {
		return text
			.trim()
			.replace(/<[^>]*>/g, ' ')
			.replace(/[\x00-\x1F\x7F]/g, ' ')
			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
			.replace(/\s{2,}/g, ' ')
			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
			.trim();
	}

	private readonly QUERY_SYNONYMS: [RegExp, string][] = [
		[/\btshirt(s)?\b/gi, 't-shirt$1'],
		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
		[/\bv[\s-]?neck\b/gi, 'v-neck'],
		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
	];

	private normalizeQuery({ text }: { text: string }): string {
		let normalized = text.toLowerCase().trim();

		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
			normalized = normalized.replace(pattern, replacement);
		}

		return normalized;
	}

	@LogExecution()
	async createProductsIndex({ indexName }: { indexName: string }): Promise<void> {
		const settings = {
			number_of_shards: 3,
			number_of_replicas: 1,
			'index.knn': true,
			'index.knn.algo_param.ef_search': 512,
			default_pipeline: 'products-neural-pipeline',
		};

		const mappings = {
			properties: {
				style_id: { type: 'long' },
				product_id: { type: 'long' },
				name: { type: 'text' },
				features: { type: 'text' },
				general_comments: { type: 'text' },
				decoration_method: { type: 'text' },
				manufacturer: { type: 'text' },
				primary_category_id: { type: 'integer' },
				primary_category_name: { type: 'keyword' },
				product_type: { type: 'keyword' },
				style_type: { type: 'keyword' },
				broad_category_names: { type: 'keyword' },
				sub_category_names: { type: 'keyword' },
				minimum_quantity: { type: 'integer' },
				min_qty: { type: 'integer' },
				default_quote_qty: { type: 'integer' },
				sizes: { type: 'keyword' },
				turn_time: { type: 'integer' },
				rush_turn_time: { type: 'integer' },
				no_minimum: { type: 'byte' },
				price_level: { type: 'short' },
				rating_score: { type: 'float' },
				rating_count: { type: 'integer' },
				default_unit_prices: {
					type: 'nested',
					properties: {
						quantity: { type: 'integer' },
						price: { type: 'keyword' },
						regular_unit_price: { type: 'keyword' },
						algorithm: { type: 'keyword' },
					},
				},
				colors: {
					type: 'nested',
					properties: {
						name: { type: 'keyword' },
						id: { type: 'integer' },
						rbgs: {
							type: 'nested',
							properties: {
								R: { type: 'short' },
								G: { type: 'short' },
								B: { type: 'short' },
							},
						},
						image_url: { type: 'keyword' },
					},
				},
				price: { type: 'float' },
				style_card_image_url: { type: 'keyword' },
				link: { type: 'keyword' },
				brand: { type: 'keyword' },
				condensed_features: { type: 'keyword' },
				material: { type: 'keyword' },
				status: { type: 'keyword' },
				created_at: { type: 'date' },
				updated_at: { type: 'date' },
				deleted_at: { type: 'date' },
				combined_text_for_embedding: { type: 'text' },
				product_embedding: {
					type: 'knn_vector',
					dimension: 768,
					method: {
						name: 'hnsw',
						space_type: 'l2',
						engine: 'faiss',
						parameters: { ef_construction: 512, m: 48 },
					},
				},
			},
		};

		await this.opensearchService.createIndex({ indexName, mappings, settings });
	}

	@LogExecution({ logParams: false, logResponse: false })
	async bulkIndexProducts({
		indexName,
		styles,
	}: {
		indexName: string;
		styles: IStylesMvBase[];
	}): Promise<{ indexed: number; errors: number }> {
		if (styles.length === 0) {
			return { indexed: 0, errors: 0 };
		}

		const documents = styles.map((style) =>
			this.transformStyleToOpensearchProduct({ style }),
		);

		return this.opensearchService.bulkIndex({ indexName, documents });
	}

	@LogExecution({
		paramFormatter: (
			params: [{ queryText: string; size: number; categoryFilter?: string }],
		) => ({
			queryText: params[0].queryText,
			size: params[0].size,
			categoryFilter: params[0].categoryFilter,
		}),
		responseFormatter: (response: IOpensearchProduct[]) => ({
			totalResults: response.length,
		}),
	})
	async searchProducts({
		queryText,
		size = NEURAL_SEARCH_LIMIT,
		categoryFilter,
	}: {
		queryText: string;
		size?: number;
		categoryFilter?: string;
	}): Promise<IOpensearchProduct[]> {
		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
		const brand = this.detectBrand({ text: sanitizedQuery });
		const detectedColor = this.detectColor({ text: sanitizedQuery });
		const detectedSize = this.detectSize({ text: sanitizedQuery });
		const detectedPriceRange = this.detectPriceRange({ text: queryText });

		const baseFilters: object[] = [
			{ term: { status: 'active' } },
			...(categoryFilter
				? [
						{
							bool: {
								should: [
									{ term: { broad_category_names: categoryFilter } },
									{ term: { sub_category_names: categoryFilter } },
								],
								minimum_should_match: 1,
							},
						},
					]
				: []),
		];

		const genderBoosts: object[] = genderProductTypes
			? [{ terms: { product_type: genderProductTypes } }]
			: [];

		const priceBoosts: object[] =
			priceLevels?.map((level) => ({
				term: { price_level: { value: level } },
			})) ?? [];

		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand] } }] : [];

		const colorBoosts: object[] = detectedColor
			? [
					{
						nested: {
							path: 'colors',
							query: {
								wildcard: {
									'colors.name': {
										value: `*${detectedColor.toLowerCase()}*`,
										case_insensitive: true,
									},
								},
							},
						},
					},
				]
			: [];

		const unitPriceBoosts: object[] = detectedPriceRange
			? [
					{
						range: {
							price: {
								...(detectedPriceRange.min !== null && { gte: detectedPriceRange.min }),
								...(detectedPriceRange.max !== null && { lte: detectedPriceRange.max }),
							},
						},
					},
				]
			: [];

		const sizeBoosts: object[] = detectedSize
			? [
					{
						wildcard: {
							sizes: { value: `*${detectedSize.toLowerCase()}*`, case_insensitive: true },
						},
					},
				]
			: [];

		const hits = await this.opensearchService.search({
			indexName: this.indexName,
			searchPipeline: 'hybrid-search-pipeline',
			body: {
				size,
				min_score: 0.4,
				query: {
					hybrid: {
						queries: [
							{
								bool: {
									should: [
										{ match: { name: { query: normalizedQuery, boost: 0.1 } } },
										{
											match: {
												condensed_features: { query: normalizedQuery, boost: 0.3 },
											},
										},
										...priceBoosts,
										...brandBoosts,
										...genderBoosts,
										...colorBoosts,
										...sizeBoosts,
										...unitPriceBoosts,
									],
									filter: baseFilters,
								},
							},
							{
								neural: {
									product_embedding: {
										query_text: normalizedQuery,
										model_id: this.getModelId(),
										k: size * 5,
										filter: { bool: { filter: baseFilters } },
									},
								},
							},
						],
					},
				},
				collapse: { field: 'product_id' },
				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
			},
		});

		const maxScore = Math.max(...hits.map((hit) => hit._score), 1);

		return hits.map((hit) => {
			const product = hit._source as IOpensearchProduct;
			const imageUrl = detectedColor
				? this.resolveColorImageUrl({ product, colorName: detectedColor })
				: null;
			const normalizedScore = hit._score / maxScore;

			return {
				...product,
				_id: hit._id,
				confidenceScore: Math.min(Math.round(Math.pow(normalizedScore, 2) * 100), 100),
				...(imageUrl !== null && { style_card_image_url: imageUrl }),
			};
		});
	}

	@LogExecution({
		paramFormatter: (
			params: [{ categories: Record<string, string>[]; size?: number }],
		) => ({
			categories: params[0].categories.map((c) => Object.keys(c)[0]),
			size: params[0].size,
		}),
		responseFormatter: (response: IOpensearchProduct[]) => ({
			total: response.length,
		}),
	})
	async searchProductsByCategories({
		categories,
		size,
	}: {
		categories: Record<string, string>[];
		size?: number;
	}): Promise<IOpensearchProduct[]> {
		const effectiveSize = size ?? NEURAL_SEARCH_LIMIT;
		const perCategory = Math.ceil(effectiveSize / categories.length);

		const categoryResults = await Promise.all(
			categories.map((categoryEntry) => {
				const categoryName = Object.keys(categoryEntry)[0] ?? '';
				const categoryQueryText = Object.values(categoryEntry)[0] ?? '';

				return this.searchProducts({
					queryText: categoryQueryText || categoryName,
					size: perCategory,
					categoryFilter: categoryName,
				});
			}),
		);

		const interleaved: IOpensearchProduct[] = [];
		const maxLen = Math.max(...categoryResults.map((r) => r.length));
		for (let i = 0; i < maxLen; i++) {
			for (const results of categoryResults) {
				const item = results[i];
				if (item !== undefined) {
					interleaved.push(item);
				}
			}
		}

		return interleaved.slice(0, effectiveSize);
	}

	private resolveColorImageUrl({
		product,
		colorName,
	}: {
		product: IOpensearchProduct;
		colorName: string;
	}): string | null {
		if (!product.colors?.length) return null;

		const lowerColor = colorName.toLowerCase();
		const match = product.colors.find((c) => c.name.toLowerCase() === lowerColor);

		if (match?.image_url) return match.image_url;

		const partialMatch = product.colors.find((c) =>
			c.name.toLowerCase().includes(lowerColor),
		);

		return partialMatch?.image_url ?? null;
	}

	private normalizeCondensedFeatures({
		condensedFeatures,
	}: {
		condensedFeatures: unknown;
	}): string[] | null {
		if (condensedFeatures === null || condensedFeatures === undefined) {
			return null;
		}

		if (typeof condensedFeatures === 'string') {
			return [condensedFeatures];
		}

		if (Array.isArray(condensedFeatures)) {
			return condensedFeatures.map(String);
		}

		if (typeof condensedFeatures === 'object') {
			return Object.values(condensedFeatures).flatMap((value: unknown) =>
				Array.isArray(value) ? value.map(String) : [String(value)],
			);
		}

		return [JSON.stringify(condensedFeatures)];
	}

	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
			condensedFeatures: style.condensed_features,
		});
		const priceLvlMap: Record<string, string> = {
			1: 'Budget',
			2: 'Mid-range',
			3: 'Premium',
		};
		const mappedPriceLevel: string | null =
			style.price_level && priceLvlMap[String(style.price_level)]
				? (priceLvlMap[String(style.price_level)] ?? null)
				: (priceLvlMap['2'] ?? null);

		const parts: string[] = [
			...(style.name ? [this.cleanText({ text: style.name })] : []),
			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
			...(style.brand?.length
				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
				: []),
			...(normalizedCondensedFeatures?.length
				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
				: []),
			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
			...(style.primary_category_name
				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
				: []),
			...(style.manufacturer
				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
				: []),
			...(style.sub_category_names?.length
				? [
						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
					]
				: []),
			...(style.decoration_method
				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
				: []),
			...(style.features
				? [`Features: ${this.cleanText({ text: style.features })}`]
				: []),
		];

		const combinedText = parts.filter(Boolean).join('. ');

		this.logger.debug(
			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
		);

		return combinedText;
	}

	private extractPrice({
		prices,
	}: {
		prices: IOpensearchProduct['default_unit_prices'];
	}): number | null {
		if (!prices?.length) return null;
		const first = prices[0];
		if (!first) return null;
		const parsed = parseFloat(first.price);
		return isNaN(parsed) ? null : parsed;
	}

	private cleanText({ text }: { text: string | null | undefined }): string {
		if (!text) return '';
		return text
			.replace(/\r\n|\r|\n/g, ' ')
			.replace(/[*#]+\s?/g, '')
			.replace(/<[^>]*>/g, '')
			.replace(/\s{2,}/g, ' ')
			.trim();
	}

	private transformStyleToOpensearchProduct({
		style,
	}: {
		style: IStylesMvBase;
	}): IOpensearchProduct {
		return {
			_id: style._id,
			style_id: style.style_id,
			product_id: style.product_id,
			name: style.name ?? '',
			features: style.features,
			general_comments: style.general_comments,
			decoration_method: style.decoration_method,
			manufacturer: style.manufacturer,
			primary_category_id: style.primary_category_id,
			primary_category_name: style.primary_category_name,
			product_type: style.product_type,
			style_type: style.style_type,
			broad_category_names: style.broad_category_names,
			sub_category_names: style.sub_category_names,
			minimum_quantity: style.minimum_quantity,
			min_qty: style.min_qty,
			default_quote_qty: style.default_quote_qty,
			sizes: style.sizes,
			turn_time: style.turn_time,
			rush_turn_time: style.rush_turn_time,
			no_minimum: style.no_minimum ? 1 : 0,
			price_level: style.price_level,
			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
			rating_count: style.rating_count,
			default_unit_prices: style.default_unit_prices,
			price: this.extractPrice({ prices: style.default_unit_prices }),
			colors: style.colors,
			style_card_image_url: style.style_card_image_url,
			link: style.link,
			brand: style.brand,
			condensed_features: this.normalizeCondensedFeatures({
				condensedFeatures: style.condensed_features,
			}),
			material: style.material,
			status: style.status,
			created_at:
				style.created_at instanceof Date
					? style.created_at.toISOString()
					: String(style.created_at),
			updated_at:
				style.updated_at instanceof Date
					? style.updated_at.toISOString()
					: String(style.updated_at),
			deleted_at: style.deleted_at
				? style.deleted_at instanceof Date
					? style.deleted_at.toISOString()
					: String(style.deleted_at)
				: null,
			combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
		};
	}
}

