import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { Client } from '@opensearch-project/opensearch';

import { EnvConfigService } from '@modules/env-config/env-config.service';

import {
	OPENSEARCH_HOST,
	OPENSEARCH_PASSWORD,
	OPENSEARCH_USERNAME,
} from '@constants/env-variables.constant';

import { LogExecution } from '@decorators/log-execution.decorator';

@Injectable()
export class OpensearchService implements OnModuleInit {
	private readonly logger = new Logger(OpensearchService.name);
	private client: Client;
	private host: string;
	private username: string;
	private password: string;

	constructor(private readonly configService: EnvConfigService) {}

	onModuleInit(): void {
		this.initializeOpensearchClient();
	}

	private initializeOpensearchClient(): void {
		try {
			this.host = this.configService.get<string>({ key: OPENSEARCH_HOST });
			this.username = this.configService.get<string>({ key: OPENSEARCH_USERNAME });
			this.password = this.configService.get<string>({ key: OPENSEARCH_PASSWORD });

			this.client = new Client({
				node: this.host,
				auth: {
					username: this.username,
					password: this.password,
				},
			});

			this.logger.log(`OpenSearch client initialized successfully. Host: ${this.host}`);
		} catch (error: unknown) {
			this.handleError({ context: 'Failed to initialize OpenSearch client', error });
			throw error;
		}
	}

	@LogExecution()
	async healthCheck(): Promise<{ status: string; cluster_name: string }> {
		try {
			const response = await this.client.cluster.health();
			return {
				status: response.body.status,
				cluster_name: response.body.cluster_name,
			};
		} catch (error: unknown) {
			this.handleError({ context: 'OpenSearch health check failed', error });
			throw error;
		}
	}

	getClient(): Client {
		return this.client;
	}

	@LogExecution()
	async createIndex({
		indexName,
		mappings,
		settings,
	}: {
		indexName: string;
		mappings: Record<string, unknown>;
		settings: Record<string, unknown>;
	}): Promise<void> {
		try {
			const exists = await this.client.indices.exists({ index: indexName });

			if (exists.body) {
				this.logger.log(`Index ${indexName} already exists`);
				return;
			}

			await this.client.indices.create({
				index: indexName,
				body: {
					settings,
					mappings,
				},
			});

			this.logger.log(`Created OpenSearch index: ${indexName}`);
		} catch (error: unknown) {
			this.handleError({ context: `Failed to create index ${indexName}`, error });
			throw error;
		}
	}

	@LogExecution({ logParams: false, logResponse: false })
	async bulkIndex({
		indexName,
		documents,
	}: {
		indexName: string;
		documents: { _id: string; [key: string]: unknown }[];
	}): Promise<{ indexed: number; errors: number }> {
		try {
			if (documents.length === 0) {
				return { indexed: 0, errors: 0 };
			}

			const body = documents.flatMap((doc) => {
				const { _id, ...docWithoutId } = doc;
				return [{ index: { _index: indexName, _id } }, docWithoutId];
			});

			const response = await this.client.bulk({ body });

			const errorItems = response.body.items.filter(
				(item: { index?: { error?: unknown } }) => item.index?.error,
			);

			const errors = errorItems.length;
			const indexed = documents.length - errors;

			if (errors > 0) {
				this.logger.warn(
					`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
				);

				const sampleErrors = errorItems
					.slice(0, 3)
					.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
						type: item.index?.error?.type,
						reason: item.index?.error?.reason,
					}));

				this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
			}

			return { indexed, errors };
		} catch (error: unknown) {
			this.handleError({ context: 'Bulk index failed', error });
			throw error;
		}
	}

	@LogExecution()
	async configureClusterMLSettings(): Promise<void> {
		try {
			await this.client.cluster.putSettings({
				body: {
					persistent: {
						'plugins.ml_commons.only_run_on_ml_node': false,
						'plugins.ml_commons.model_access_control_enabled': true,
						'plugins.ml_commons.native_memory_threshold': 99,
					},
				},
			});
			this.logger.log('Configured ML cluster settings');
		} catch (error: unknown) {
			this.handleError({ context: 'Failed to configure ML cluster settings', error });
			throw error;
		}
	}

	@LogExecution()
	async registerModelGroup({
		name,
		description,
	}: {
		name: string;
		description: string;
	}): Promise<string> {
		try {
			const response = await this.client.transport.request({
				method: 'POST',
				path: '/_plugins/_ml/model_groups/_register',
				body: { name, description },
			});

			const modelGroupId = (response.body as { model_group_id: string }).model_group_id;
			this.logger.log(`Registered model group: ${modelGroupId}`);
			return modelGroupId;
		} catch (error: unknown) {
			this.handleError({ context: 'Failed to register model group', error });
			throw error;
		}
	}

	@LogExecution()
	async registerModel({
		name,
		version,
		modelGroupId,
		modelFormat,
	}: {
		name: string;
		version: string;
		modelGroupId: string;
		modelFormat: string;
	}): Promise<string> {
		try {
			const response = await this.client.transport.request({
				method: 'POST',
				path: '/_plugins/_ml/models/_register',
				body: {
					name,
					version,
					model_group_id: modelGroupId,
					model_format: modelFormat,
				},
			});

			const taskId = (response.body as { task_id: string }).task_id;
			this.logger.log(`Model registration started, taskId: ${taskId}`);
			return taskId;
		} catch (error: unknown) {
			this.handleError({ context: 'Failed to register model', error });
			throw error;
		}
	}

	@LogExecution()
	async deployModel({ modelId }: { modelId: string }): Promise<string> {
		try {
			const response = await this.client.transport.request({
				method: 'POST',
				path: `/_plugins/_ml/models/${modelId}/_deploy`,
			});

			const taskId = (response.body as { task_id: string }).task_id;
			this.logger.log(`Model deployment started, taskId: ${taskId}`);
			return taskId;
		} catch (error: unknown) {
			this.handleError({ context: `Failed to deploy model ${modelId}`, error });
			throw error;
		}
	}

	@LogExecution()
	async getTask({ taskId }: { taskId: string }): Promise<{
		state: string;
		model_id?: string;
	}> {
		try {
			const response = await this.client.transport.request({
				method: 'GET',
				path: `/_plugins/_ml/tasks/${taskId}`,
			});

			const body = response.body as { state: string; model_id?: string };
			return {
				state: body.state,
				...(body.model_id !== undefined && { model_id: body.model_id }),
			};
		} catch (error: unknown) {
			this.handleError({ context: `Failed to get task ${taskId}`, error });
			throw error;
		}
	}

	@LogExecution()
	async waitForTask({
		taskId,
		intervalMs = 5000,
		maxAttempts = 60,
	}: {
		taskId: string;
		intervalMs?: number;
		maxAttempts?: number;
	}): Promise<{ state: string; model_id?: string }> {
		for (let attempt = 1; attempt <= maxAttempts; attempt++) {
			const task = await this.getTask({ taskId });
			this.logger.log(
				`Task ${taskId} — attempt ${attempt}/${maxAttempts}, state: ${task.state}`,
			);

			if (task.state === 'COMPLETED') {
				return task;
			}

			if (task.state === 'FAILED') {
				throw new Error(`Task ${taskId} failed`);
			}

			await new Promise((resolve) => setTimeout(resolve, intervalMs));
		}

		throw new Error(`Task ${taskId} timed out after ${maxAttempts} attempts`);
	}

	@LogExecution()
	async createIngestPipeline({
		pipelineId,
		modelId,
		sourceField,
		targetField,
	}: {
		pipelineId: string;
		modelId: string;
		sourceField: string;
		targetField: string;
	}): Promise<void> {
		try {
			await this.client.ingest.putPipeline({
				id: pipelineId,
				body: {
					description: `Neural search ingest pipeline: ${sourceField} -> ${targetField}`,
					processors: [
						{
							text_embedding: {
								model_id: modelId,
								field_map: {
									[sourceField]: targetField,
								},
							},
						},
					],
				},
			});
			this.logger.log(`Created ingest pipeline: ${pipelineId}`);
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to create ingest pipeline ${pipelineId}`,
				error,
			});
			throw error;
		}
	}

	@LogExecution()
	async createSearchPipeline({
		pipelineId,
		normalizationTechnique = 'min_max',
		combinationTechnique = 'arithmetic_mean',
		weights = [0.2, 0.8],
	}: {
		pipelineId: string;
		normalizationTechnique?: string;
		combinationTechnique?: string;
		weights?: number[];
	}): Promise<void> {
		try {
			await this.client.transport.request({
				method: 'PUT',
				path: `/_search/pipeline/${pipelineId}`,
				body: {
					description: `Hybrid search pipeline: ${normalizationTechnique} + ${combinationTechnique}`,
					phase_results_processors: [
						{
							'normalization-processor': {
								normalization: { technique: normalizationTechnique },
								combination: { technique: combinationTechnique, parameters: { weights } },
							},
						},
					],
				},
			});
			this.logger.log(`Created search pipeline: ${pipelineId}`);
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to create search pipeline ${pipelineId}`,
				error,
			});
			throw error;
		}
	}

	@LogExecution({
		paramFormatter: (params: [{ indexName: string; searchPipeline?: string }]) => ({
			indexName: params[0].indexName,
			searchPipeline: params[0].searchPipeline,
		}),
	})
	async search({
		indexName,
		body,
		searchPipeline,
	}: {
		indexName: string;
