			this.logger.log(`Undeployed model: ${modelId}`);
		} catch (error: unknown) {
			this.handleError({ context: `Failed to undeploy model ${modelId}`, error });
			throw error;
		}
	}

	@LogExecution()
	async deleteModel({ modelId }: { modelId: string }): Promise<void> {
		try {
			await this.client.transport.request({
				method: 'DELETE',
				path: `/_plugins/_ml/models/${modelId}`,
			});
			this.logger.log(`Deleted model: ${modelId}`);
		} catch (error: unknown) {
			this.handleError({ context: `Failed to delete model ${modelId}`, error });
			throw error;
		}
	}

	@LogExecution()
	async deleteModelGroup({ modelGroupId }: { modelGroupId: string }): Promise<void> {
		try {
			await this.client.transport.request({
				method: 'DELETE',
				path: `/_plugins/_ml/model_groups/${modelGroupId}`,
			});
			this.logger.log(`Deleted model group: ${modelGroupId}`);
		} catch (error: unknown) {
			this.handleError({
				context: `Failed to delete model group ${modelGroupId}`,
				error,
			});
			throw error;
		}
	}

	@LogExecution()
	async findDeployedModelId({
		modelGroupName,
	}: {
		modelGroupName: string;
	}): Promise<string | null> {
		const modelGroupId = await this.searchModelGroupByName({ name: modelGroupName });

		if (!modelGroupId) {
			return null;
		}

		const models = await this.searchModelsByGroup({ modelGroupId });
		const deployed = models.find((m) => m.model_state === 'DEPLOYED');
		return deployed?.model_id ?? null;
	}

	private isNotFoundError({ error }: { error: unknown }): boolean {
		const message = error instanceof Error ? error.message : String(error);
		return message.includes('resource_not_found') || message.includes('404');
	}

	private handleError({ context, error }: { context: string; error: unknown }): void {
		const err = error instanceof Error ? error : new Error(String(error));
		this.logger.error(`${context}: ${err.message}`, err.stack);
	}
}

