import { Logger } from '@nestjs/common';
import { Command, CommandRunner, Option } from 'nest-commander';

import { OpensearchService } from '@modules/opensearch/opensearch.service';

import { CronJobExecution } from '@decorators/cron-job-execution.decorator';

const MODEL_NAME = 'huggingface/sentence-transformers/all-distilroberta-v1';
const MODEL_VERSION = '1.0.1';
const MODEL_GROUP_NAME = 'neural-search-model-group';
const INGEST_PIPELINE_ID = 'products-neural-pipeline';
const SEARCH_PIPELINE_ID = 'hybrid-search-pipeline';

interface SetupNeuralSearchOptions {
	modelFormat?: string;
	skipClusterSettings?: boolean;
	skipModelSetup?: boolean;
	skipPipelines?: boolean;
}

@Command({
	name: 'setup-neural-search',
	description:
		'Bootstrap ML pipeline for neural search: register model, deploy, create pipelines',
})
export class SetupNeuralSearchCommand extends CommandRunner {
	private readonly logger = new Logger(SetupNeuralSearchCommand.name);

	constructor(private readonly opensearchService: OpensearchService) {
		super();
	}

	@CronJobExecution({ jobName: 'setup-neural-search' })
	async run(_passedParams: string[], options: SetupNeuralSearchOptions): Promise<void> {
		const modelFormat = options.modelFormat ?? 'TORCH_SCRIPT';
		const skipClusterSettings = options.skipClusterSettings ?? false;
		const skipModelSetup = options.skipModelSetup ?? false;
		const skipPipelines = options.skipPipelines ?? false;

		try {
			if (!skipClusterSettings) {
				this.logger.log('Step 1: Configuring cluster ML settings...');
				await this.opensearchService.configureClusterMLSettings();
			}

			let modelId: string | undefined;

			if (!skipModelSetup) {
				this.logger.log('Step 2: Registering model group...');
				const modelGroupId = await this.opensearchService.registerModelGroup({
					name: MODEL_GROUP_NAME,
					description: 'Model group for neural search embeddings',
				});

				this.logger.log('Step 3: Registering model...');
				const registerTaskId = await this.opensearchService.registerModel({
					name: MODEL_NAME,
					version: MODEL_VERSION,
					modelGroupId,
					modelFormat,
				});

				this.logger.log('Step 4: Waiting for model registration...');
				const registerResult = await this.opensearchService.waitForTask({
					taskId: registerTaskId,
				});
				modelId = registerResult.model_id;

				if (!modelId) {
					throw new Error('Model registration completed but no model_id returned');
				}

				this.logger.log(`Model registered: ${modelId}`);

				this.logger.log('Step 5: Deploying model...');
				const deployTaskId = await this.opensearchService.deployModel({ modelId });

				this.logger.log('Step 6: Waiting for model deployment...');
				await this.opensearchService.waitForTask({ taskId: deployTaskId });
				this.logger.log('Model deployed successfully');
			}

			if (!skipPipelines) {
				modelId ??=
					(await this.opensearchService.findDeployedModelId({
						modelGroupName: MODEL_GROUP_NAME,
					})) ?? undefined;

				if (!modelId) {
					this.logger.error(
						'Cannot create pipelines without model_id. Run without --skip-model-setup first.',
					);
					process.exit(1);
				}

				this.logger.log('Step 7: Creating ingest pipeline...');
				await this.opensearchService.createIngestPipeline({
					pipelineId: INGEST_PIPELINE_ID,
					modelId,
					sourceField: 'combined_text_for_embedding',
					targetField: 'product_embedding',
				});

				this.logger.log('Step 8: Creating search pipeline...');
				await this.opensearchService.createSearchPipeline({
					pipelineId: SEARCH_PIPELINE_ID,
					normalizationTechnique: 'min_max',
					combinationTechnique: 'arithmetic_mean',
					weights: [0.2, 0.8],
				});
			}

			this.logger.log('Neural search setup completed successfully');

			if (modelId) {
				this.logger.log(`Model ID: ${modelId} (resolved dynamically at app startup)`);
			}
		} catch (error) {
			this.logger.error(`Setup failed: ${(error as Error).message}`);
			process.exit(1);
		}
	}

	@Option({
		flags: '-f, --model-format <modelFormat>',
		description: 'Model format: TORCH_SCRIPT or ONNX (default: TORCH_SCRIPT)',
	})
	parseModelFormat(value: string): string {
		const valid = ['TORCH_SCRIPT', 'ONNX'];
		if (!valid.includes(value)) {
			throw new Error(`Model format must be one of: ${valid.join(', ')}`);
		}
		return value;
	}

	@Option({
		flags: '--skip-cluster-settings',
		description: 'Skip configuring cluster ML settings',
	})
	parseSkipClusterSettings(): boolean {
		return true;
	}

	@Option({
		flags: '--skip-model-setup',
		description: 'Skip model registration and deployment',
	})
	parseSkipModelSetup(): boolean {
		return true;
	}

	@Option({
		flags: '--skip-pipelines',
		description: 'Skip creating ingest and search pipelines',
	})
	parseSkipPipelines(): boolean {
		return true;
	}
}

