import { Logger } from '@nestjs/common';
import { Command, CommandRunner } from 'nest-commander';

import { OpensearchService } from '@modules/opensearch/opensearch.service';

import { CronJobExecution } from '@decorators/cron-job-execution.decorator';

const MODEL_GROUP_NAME = 'neural-search-model-group';

@Command({
	name: 'redeploy-neural-search',
	description:
		'Redeploy existing neural search model without re-registering or re-indexing',
})
export class RedeployNeuralSearchCommand extends CommandRunner {
	private readonly logger = new Logger(RedeployNeuralSearchCommand.name);

	constructor(private readonly opensearchService: OpensearchService) {
		super();
	}

	@CronJobExecution({ jobName: 'redeploy-neural-search' })
	async run(): Promise<void> {
		try {
			this.logger.log('Attempting to redeploy existing neural search model...');

			const modelId = await this.opensearchService.redeployRegisteredModel({
				modelGroupName: MODEL_GROUP_NAME,
			});

			if (!modelId) {
				this.logger.warn(
					'No registered model found. Run: npm run cli:dev -- bootstrap-neural-search',
				);
				return;
			}

			this.logger.log(`Model redeployed successfully: ${modelId}`);
		} catch (error) {
			this.logger.error(`Redeploy failed: ${(error as Error).message}`);
			process.exit(1);
		}
	}
}

